/**
 * Пороги по плану (СанПиН IIб, ГОСТ 30494, паспорт КУЛТЕК R22) + разбор MQTT.
 */

const THRESHOLDS = {
  room: {
    temp_c_range: [10, 40],
    temp_c_comfort_cold: [16, 22],
    temp_c_comfort_warm: [18, 26],
    temp_warning_below: 16,
    temp_warning_above: 26,
    temp_critical_below: 14,
    temp_critical_above: 30,
    rh_pct_range: [10, 95],
    rh_pct_norm: [15, 75],
    rh_warning_below: 15,
    rh_warning_above: 75,
    rh_critical_below: 10,
    rh_critical_above: 85,
    co2_ppm_comfort: 1000,
    co2_ppm_warning: 1400,
    co2_ppm_critical: 2000,
    air_speed_ms_norm: [0.1, 0.4],
    air_speed_ms_warning_above: 0.5,
  },
  chiller_r22: {
    t_evap_c_range: [-20, 5],
    t_evap_c_nominal_c: -7.5,
    t_evap_warning_below: -15,
    t_evap_warning_above: 2,
    p_suction_bar_abs_range: [1.0, 8.0],
    p_suction_bar_abs_nominal: 3.87,
    p_discharge_bar_abs_range: [8.0, 25.0],
    p_discharge_bar_abs_nominal: 15.34,
    p_suction_warn_below: 2.5,
    p_suction_critical_below: 1.5,
    p_discharge_warn_above: 20,
    p_discharge_critical_above: 25,
    superheat_k_range: [0, 25],
    superheat_k_norm: [5, 10],
    superheat_warn_below: 3,
    superheat_warn_above: 15,
    superheat_crit_below: 1,
    superheat_crit_above: 20,
    t_discharge_c_range: [40, 160],
    t_discharge_norm: [60, 100],
    t_discharge_warn_c: 120,
    t_discharge_critical_c: 135,
    t_oil_c_range: [20, 80],
    t_oil_norm: [40, 60],
    t_oil_warn_c: 65,
    t_oil_critical_c: 75,
    oil_dp_bar_range: [0, 3.0],
    oil_dp_norm: [1.25, 1.65],
    oil_dp_warn_below: 1.1,
    oil_dp_critical_below: 0.65,
  },
  coolant_nh3_20pct: {
    t_in_c_range: [-5, 20],
    t_in_norm: [10, 14],
    t_out_c_range: [-10, 15],
    t_out_nominal: [-7.5, 0.1],
    // 20% р-р NH3 замерзает при ~-36C; -10C — аварийная защита технологического контура
    t_out_critical_below_c: -10,
    flow_m3h_range: [0, 300],
    flow_m3h_nominal_max: 250,
    flow_warn_below: 100,
    pressure_mpa_range: [0, 2.0],
    pressure_mpa_nominal_max: 1.45,
    pressure_warn_above_mpa: 1.3,
  },
  condenser_water: { t_in_c_nominal: 26, t_out_c_nominal: 33 },
  sanpin: {
    nh3_mg_m3_max: 20,
    ref: 'СанПиН 1.2.3685-21 табл. 2.1 (NH3), табл. 5.2 кат. IIб',
  },
};

function evaluateRuleSeverity(payload, H) {
  let sev = 'normal';
  const issues = [];
  function bump(level, msg) {
    issues.push(msg);
    if (level === 'critical') sev = 'critical';
    else if (level === 'warning' && sev !== 'critical') sev = 'warning';
  }
  const room = payload.room || {};
  const ch = payload.chiller || {};
  const nh3 = payload.coolant || {};
  const cond = payload.condenser || {};
  const R = H.room;
  const C = H.chiller_r22;
  const N = H.coolant_nh3_20pct;

  if (room.temp_c != null) {
    const t = Number(room.temp_c);
    if (!Number.isNaN(t)) {
      if (t < R.temp_critical_below || t > R.temp_critical_above) bump('critical', 't помещения ' + t + '°C');
      else if (t < R.temp_warning_below || t > R.temp_warning_above) bump('warning', 't помещения ' + t + '°C вне комфорта');
    }
  }
  if (room.rh_pct != null) {
    const rh = Number(room.rh_pct);
    if (!Number.isNaN(rh)) {
      if (rh < R.rh_critical_below || rh > R.rh_critical_above) bump('critical', 'RH ' + rh + '%');
      else if (rh < R.rh_warning_below || rh > R.rh_warning_above) bump('warning', 'RH ' + rh + '%');
    }
  }
  if (room.co2_ppm != null) {
    const co2 = Number(room.co2_ppm);
    if (!Number.isNaN(co2)) {
      if (co2 >= R.co2_ppm_critical) bump('critical', 'CO2 ' + co2 + ' ppm');
      else if (co2 >= R.co2_ppm_warning) bump('warning', 'CO2 ' + co2 + ' ppm');
    }
  }
  if (room.air_speed_ms != null) {
    const v = Number(room.air_speed_ms);
    if (!Number.isNaN(v) && v > R.air_speed_ms_warning_above) bump('warning', 'скорость воздуха ' + v + ' м/с');
  }

  if (ch.t_evap_c != null) {
    const te = Number(ch.t_evap_c);
    if (!Number.isNaN(te)) {
      if (te < C.t_evap_c_range[0] || te > C.t_evap_c_range[1]) bump('critical', 'T исп ' + te + '°C вне диапазона');
      else if (te < C.t_evap_warning_below || te > C.t_evap_warning_above) bump('warning', 'T исп ' + te + '°C');
    }
  }
  if (ch.p_suction_bar_abs != null) {
    const p = Number(ch.p_suction_bar_abs);
    if (!Number.isNaN(p)) {
      if (p < C.p_suction_bar_abs_range[0] || p > C.p_suction_bar_abs_range[1]) bump('critical', 'P всас ' + p + ' бар вне диапазона');
      else if (p < C.p_suction_critical_below) bump('critical', 'P всас ' + p + ' бар');
      else if (p < C.p_suction_warn_below) bump('warning', 'P всас ' + p + ' бар');
    }
  }
  if (ch.p_discharge_bar_abs != null) {
    const p = Number(ch.p_discharge_bar_abs);
    if (!Number.isNaN(p)) {
      if (p < C.p_discharge_bar_abs_range[0] || p > C.p_discharge_bar_abs_range[1]) bump('critical', 'P нагн ' + p + ' бар вне диапазона');
      else if (p >= C.p_discharge_critical_above) bump('critical', 'P нагн ' + p + ' бар');
      else if (p >= C.p_discharge_warn_above) bump('warning', 'P нагн ' + p + ' бар');
    }
  }
  if (ch.superheat_k != null) {
    const sh = Number(ch.superheat_k);
    if (!Number.isNaN(sh)) {
      if (sh < C.superheat_crit_below || sh > C.superheat_crit_above) bump('critical', 'перегрев ' + sh + ' K');
      else if (sh < C.superheat_warn_below || sh > C.superheat_warn_above) bump('warning', 'перегрев ' + sh + ' K');
    }
  }
  if (ch.t_discharge_c != null) {
    const td = Number(ch.t_discharge_c);
    if (!Number.isNaN(td)) {
      if (td >= C.t_discharge_critical_c) bump('critical', 'T нагн ' + td + '°C');
      else if (td >= C.t_discharge_warn_c) bump('warning', 'T нагн ' + td + '°C');
    }
  }
  if (ch.t_oil_c != null) {
    const to = Number(ch.t_oil_c);
    if (!Number.isNaN(to)) {
      if (to >= C.t_oil_critical_c) bump('critical', 'T масла ' + to + '°C');
      else if (to >= C.t_oil_warn_c) bump('warning', 'T масла ' + to + '°C');
    }
  }
  if (ch.oil_dp_bar != null) {
    const od = Number(ch.oil_dp_bar);
    if (!Number.isNaN(od)) {
      if (od < C.oil_dp_critical_below) bump('critical', 'ΔP масла ' + od + ' бар');
      else if (od < C.oil_dp_warn_below) bump('warning', 'ΔP масла ' + od + ' бар');
    }
  }

  const tin = nh3.t_in_c ?? nh3.coolant_t_in;
  const tout = nh3.t_out_c ?? nh3.coolant_t_out;
  const flow = nh3.flow_m3h ?? nh3.coolant_flow;
  const press = nh3.pressure_mpa ?? nh3.coolant_pressure;
  if (tout != null) {
    const t = Number(tout);
    if (!Number.isNaN(t)) {
      if (t < N.t_out_critical_below_c) bump('critical', 'T вых хладоносителя ' + t + '°C');
      else if (t < N.t_out_c_range[0] || t > N.t_out_c_range[1]) bump('warning', 'T вых хладоносителя ' + t + '°C');
    }
  }
  if (tin != null) {
    const t = Number(tin);
    if (!Number.isNaN(t) && (t < N.t_in_c_range[0] || t > N.t_in_c_range[1])) bump('warning', 'T вх хладоносителя ' + t + '°C');
  }
  if (flow != null) {
    const f = Number(flow);
    if (!Number.isNaN(f) && f < N.flow_warn_below) bump('warning', 'расход ' + f + ' м³/ч');
  }
  if (press != null) {
    const pr = Number(press);
    if (!Number.isNaN(pr) && pr > N.pressure_warn_above_mpa) bump('warning', 'давление ' + pr + ' МПа');
  }
  if (cond.t_out_c != null && H.condenser_water) {
    const t = Number(cond.t_out_c);
    if (!Number.isNaN(t) && t > H.condenser_water.t_out_c_nominal + 5) bump('warning', 'T вых конденсатора ' + t + '°C');
  }
  return { ruleSeverity: sev, ruleIssues: issues, ruleSummary: issues.length ? issues.join('; ') : 'в пределах правил' };
}


const META = {
  equipment: 'КУЛТЕК CTK CH SL34M Ex',
  refrigerant: 'R22',
  coolant: '20% водный раствор аммиака',
  ex_marking: '1 Ex d IIB T4',
};

const raw = $input.first().json;
let payload;
try {
  if (raw.message !== undefined && raw.message !== null) {
    payload = typeof raw.message === 'string' ? JSON.parse(raw.message) : raw.message;
  } else {
    payload = raw;
  }
} catch (e) {
  return [
    {
      json: {
        parseError: String(e),
        topic: raw.topic,
        raw,
        thresholds: THRESHOLDS,
        meta: META,
      },
    },
  ];
}

const ruleEval = evaluateRuleSeverity(payload, THRESHOLDS);
return [
  {
    json: {
      topic: raw.topic || payload.topic || 'unknown',
      receivedAt: new Date().toISOString(),
      sensorPayload: payload,
      thresholds: THRESHOLDS,
      meta: META,
      ruleSeverity: ruleEval.ruleSeverity,
      ruleIssues: ruleEval.ruleIssues,
      ruleSummary: ruleEval.ruleSummary,
    },
  },
];

const base = $input.first().json;
if (base.parseError) return [];
const p = base.sensorPayload || {};
const room = p.room || {};
const ch = p.chiller || {};
const nh3 = p.coolant || {};
const cond = p.condenser || {};
const time = base.receivedAt || new Date().toISOString();
const rows = [];
const EQ = 'CTK_CH_SL34M';
function add(id, type, val, unit, equipment) {
  if (val === undefined || val === null) return;
  const n = Number(val);
  if (Number.isNaN(n)) return;
  rows.push({ json: { time, sensor_id: id, sensor_type: type, value: n, unit, location: 'workshop_1', equipment: equipment ?? null } });
}
add('room_temp_c', 'temperature', room.temp_c, 'C', null);
add('room_rh_pct', 'humidity', room.rh_pct, '%', null);
add('room_co2_ppm', 'concentration', room.co2_ppm, 'ppm', null);
add('room_air_speed_ms', 'velocity', room.air_speed_ms, 'm/s', null);
add('chiller_t_evap_c', 'temperature', ch.t_evap_c, 'C', EQ);
add('chiller_p_suction_bar_abs', 'pressure', ch.p_suction_bar_abs, 'bar', EQ);
add('chiller_p_discharge_bar_abs', 'pressure', ch.p_discharge_bar_abs, 'bar', EQ);
add('chiller_superheat_k', 'superheat', ch.superheat_k, 'K', EQ);
add('chiller_t_discharge_c', 'temperature', ch.t_discharge_c, 'C', EQ);
add('chiller_t_oil_c', 'temperature', ch.t_oil_c, 'C', EQ);
add('chiller_oil_dp_bar', 'pressure', ch.oil_dp_bar, 'bar', EQ);
add('coolant_t_in_c', 'temperature', nh3.t_in_c ?? nh3.coolant_t_in, 'C', EQ);
add('coolant_t_out_c', 'temperature', nh3.t_out_c ?? nh3.coolant_t_out, 'C', EQ);
add('coolant_flow_m3h', 'flow', nh3.flow_m3h ?? nh3.coolant_flow, 'm3/h', EQ);
add('coolant_pressure_mpa', 'pressure', nh3.pressure_mpa ?? nh3.coolant_pressure, 'MPa', EQ);
add('condenser_t_in_c', 'temperature', cond.t_in_c, 'C', EQ);
add('condenser_t_out_c', 'temperature', cond.t_out_c, 'C', EQ);
return rows.length ? rows : [];

// Не передавать AI невалидные сообщения (parseError из предыдущей ноды)
const base = $input.first().json;
if (base.parseError) return [];

try {
  const g = $getWorkflowStaticData('global');
  const now = Date.now();
  if (!g.lastAiMs) g.lastAiMs = 0;
  if (now - g.lastAiMs < 120000) return [];
  g.lastAiMs = now;
} catch (e) {
  // Если static data недоступен, AI вызывается на каждое сообщение (редко: только после gate отклонений)
}
return $input.all();

parameters.text:
=Ты получаешь JSON-снимок датчиков (до 15+ полей) и таблицу порогов.

**Данные:**
{{ JSON.stringify($json.sensorPayload, null, 2) }}

**Пороги / номиналы:**
{{ JSON.stringify($json.thresholds, null, 2) }}

**Оборудование:** {{ $json.meta.equipment }} | {{ $json.meta.refrigerant }} | {{ $json.meta.coolant }} | {{ $json.meta.ex_marking }}

**Предоценка правилами (минимум такой уровень):** {{ $json.ruleSeverity }} — {{ $json.ruleSummary }}

Верни один JSON-объект (без markdown), строго в формате плана:
{"status":"normal|warning|critical","alert_level":"info|warning|critical","problem":"","details":"","action":{"target":"ventilation|chiller|alarm|none","command":"","parameters":{}},"message":"текст для Telegram"}
Также продублируй severity тем же смыслом что и status (для совместимости).

