const item = $input.first().json;
const base = $('Разбор MQTT + пороги').first().json;
let text = item.output ?? item.text ?? '';
if (typeof text !== 'string') text = JSON.stringify(text);

let analysis;
try {
  const m = text.match(/\{[\s\S]*\}/);
  analysis = m ? JSON.parse(m[0]) : {
    status: 'normal',
    severity: 'normal',
    alert_level: 'info',
    problem: 'no-json',
    details: text,
    message: text.substring(0, 500),
  };
} catch (e) {
  analysis = {
    status: 'normal',
    severity: 'normal',
    alert_level: 'info',
    problem: 'parse-error',
    details: String(e),
    message: text.substring(0, 500),
  };
}

const sev = String(analysis.severity || analysis.status || 'normal').toLowerCase();
if (!analysis.severity && analysis.status) analysis.severity = analysis.status;
const al = String(analysis.alert_level || 'info').toLowerCase();
const routeSeverity = sev === 'critical' || al === 'critical' ? 'critical' : sev === 'warning' || al === 'warning' ? 'warning' : 'normal';

return [{ json: { ...base, analysis, routeSeverity, alertLevel: al } }];

const j = $input.first().json;
if (j.parseError) return [];
if (j.ruleSeverity === 'normal' || !j.ruleSeverity) return [];
return $input.all();
